        (entries) => {
            entries.forEach((entry) => {
                if (entry.isIntersecting) entry.target.classList.add('visible');
            });
        },
        { threshold: 0.1 }
    );
    document.querySelectorAll('.platform-section').forEach((s) => observer.observe(s));

